class Solution:
    def cellsInRange(self, s):
        c1, r1, c2, r2 = s[0], int(s[1]), s[3], int(s[4])
        res = []
        for c in range(ord(c1), ord(c2) + 1):
            for r in range(r1, r2 + 1):
                res.append(chr(c) + str(r))
        return res

