var cellsInRange = function(s) {
    const c1 = s.charCodeAt(0), r1 = s.charCodeAt(1) - 48;
    const c2 = s.charCodeAt(3), r2 = s.charCodeAt(4) - 48;
    const res = [];
    for (let c = c1; c <= c2; c++) {
        for (let r = r1; r <= r2; r++) {
            res.push(String.fromCharCode(c) + String(r));
        }
    }
    return res;
};
